 1→export function distance(a, b) {
 2→  const dx = b.x - a.x;
 3→  const dy = b.y - a.y;
 4→  return Math.sqrt(dx * dx + dy * dy);
 5→}
 6→
 7→export function midpoint(a, b) {
 8→  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
 9→}
10→
11→export function lerp(a, b, t) {
12→  return { x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t };
13→}
14→
15→export function rotate(point, center, angleDeg) {
16→  const rad = (angleDeg * Math.PI) / 180;
17→  const cos = Math.cos(rad);
18→  const sin = Math.sin(rad);
19→  const dx = point.x - center.x;
20→  const dy = point.y - center.y;
21→  return {
22→    x: center.x + dx * cos - dy * sin,
23→    y: center.y + dx * sin + dy * cos,
24→  };
25→}
26→
27→export function add(a, b) {
28→  return { x: a.x + b.x, y: a.y + b.y };
29→}
30→
31→export function subtract(a, b) {
32→  return { x: a.x - b.x, y: a.y - b.y };
33→}
34→
35→export function scale(p, s) {
36→  return { x: p.x * s, y: p.y * s };
37→}
38→
39→export function normalize(p) {
40→  const len = Math.sqrt(p.x * p.x + p.y * p.y);
41→  if (len === 0) return { x: 0, y: 0 };
42→  return { x: p.x / len, y: p.y / len };
43→}
44→
45→export function perpendicular(p) {
46→  return { x: -p.y, y: p.x };
47→}
48→
49→export function dot(a, b) {
50→  return a.x * b.x + a.y * b.y;
51→}
