154→export function useProject() {
155→  const ctx = useContext(ProjectContext);
156→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
157→  const { state, dispatch } = ctx;
158→
159→  return {
160→    project: state.project,
161→    isDirty: state.isDirty,
162→    lastSavedAt: state.lastSavedAt,
163→    dispatch,
164→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
165→  };
