 1→import { serializeProject } from './serialize';
 2→import { deserializeProject } from './deserialize';
 3→
 4→const INDEX_KEY = 'apartment-planner-projects';
 5→const PROJECT_PREFIX = 'apartment-planner-project-';
 6→
 7→function getIndex() {
 8→  try {
 9→    const raw = localStorage.getItem(INDEX_KEY);
10→    return raw ? JSON.parse(raw) : [];
11→  } catch {
12→    return [];
13→  }
14→}
15→
16→function saveIndex(index) {
17→  localStorage.setItem(INDEX_KEY, JSON.stringify(index));
18→}
19→
20→export function saveProject(project) {
21→  const serialized = serializeProject(project);
22→  const key = PROJECT_PREFIX + project.id;
23→  localStorage.setItem(key, JSON.stringify(serialized));
24→
25→  // Update index
26→  const index = getIndex();
27→  const existing = index.findIndex(p => p.id === project.id);
28→  const entry = { id: project.id, name: project.name, savedAt: serialized.savedAt };
29→
30→  if (existing >= 0) {
31→    index[existing] = entry;
32→  } else {
33→    index.push(entry);
34→  }
35→  saveIndex(index);
36→
37→  return serialized.savedAt;
38→}
39→
40→export function loadProject(projectId) {
41→  const key = PROJECT_PREFIX + projectId;
42→  const raw = localStorage.getItem(key);
43→  if (!raw) throw new Error('Project not found');
44→
45→  const json = JSON.parse(raw);
46→  return deserializeProject(json);
47→}
48→
49→export function listProjects() {
50→  return getIndex();
51→}
52→
53→export function deleteProject(projectId) {
54→  const key = PROJECT_PREFIX + projectId;
55→  localStorage.removeItem(key);
56→
57→  const index = getIndex().filter(p => p.id !== projectId);
58→  saveIndex(index);
59→}
